import React from "react";
import { graphql } from "gatsby";
import { initializeApp } from "firebase/app";
import { getFirestore } from "firebase/firestore/lite";
// import Layout from "@components/layout";
// import BreadCrumb from "@components/common/breadcrumb";
import Seo from "@components/seo";
import DecentralizedExchangeScreen from "@screens/decentralized-exchange-dev";
import { useLocation } from "@reach/router";
import Layout_v2 from "@components/layout_v2";
import BreadCrumbV2 from "@components/common/breadcrumb-v2";

const DecentralizeExchangePage = (props) => {
  const app = initializeApp(props?.data?.site?.siteMetadata?.firestore);
  const db = getFirestore(app);
  const breadcrumbLinks = [
    { text: "Home", link: "/" },
    { text: "Decentralized Exchange Development Company", link: "" },
  ];

  const { data } = props;
  const fileUrl =
    data?.decenterlizeExImg?.childImageSharp?.gatsbyImageData?.images?.fallback
      ?.src;
  const location = useLocation();
  const validData = data?.allMetaJson?.nodes[0];
  const schemaMarkup = {
    "@context": "https://schema.org",
    "@graph": [
      {
        "@type": "Organization",

        name: "Justtry Technologies",
        url: "https://justtrytech.com",
        logo: "https://justtrytech.com/static/company_logo-a8a6f67b23da723440dd6bdb258ac7e8.svg",
        description:
          "Justtry Technologies builds secure, audited DEX platforms and smart contracts, offering scalable blockchain solutions for DeFi, NFTs, and enterprises.",
        sameAs: [
          "https://www.linkedin.com/company/justtry-technologies",
          "https://twitter.com/justtrytech",
        ],
        email: "sales@justtrytech.com",
        telephone: "+91 9500139200",
        address: {
          "@type": "PostalAddress",
          streetAddress:
            "179/3, Kamarajar salai, (Near Tamilnadu Chamber of Commerce), Madurai – 625009.",
          addressLocality: "Madurai",
          addressCountry: "IN",
          addressRegion: "Tamilnadu",
          postalCode: "625009",
        },
        aggregateRating: {
          "@type": "AggregateRating",
          ratingValue: "4.8",
          reviewCount: "1821",
        },
      },
      {
        "@type": "FAQPage",

        mainEntity: [
          {
            "@type": "Question",
            name: "What are the decentralized exchanges?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "The Decentralized exchanges (DEXs) are blockchain-based platforms that let users trade cryptocurrencies directly from their wallets without a central authority.",
            },
          },
          {
            "@type": "Question",
            name: "Is decentralized exchange safe?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "Yes, decentralized exchanges are usually safe since users are in charge of their funds, yet security is determined by the quality of smart contracts, audits and user practices.",
            },
          },
          {
            "@type": "Question",
            name: "How does Dex make money?",
            acceptedAnswer: {
              "@type": "Answer",
              text: "To earn money, decentralized exchanges charge trading fees, liquidity provider fees, listing fees and occasionally native tokens issued to governance or rewards.",
            },
          },
        ],
      },
    ],
  };

  return (
    <Layout_v2 db={db}>
      <Seo
        title={validData?.title}
        metaTitle={validData?.metaTitle}
        metaKeyword={validData?.metaKeyword}
        description={validData?.description}
        image={fileUrl}
        siteFirestore={data?.site?.siteMetadata?.firestore}
        slug={location.pathname.split("/")?.[1]}
        schemaMarkup={schemaMarkup}
      ></Seo>
      <BreadCrumbV2 items={breadcrumbLinks} />
      <DecentralizedExchangeScreen db={db} />
    </Layout_v2>
  );
};

export default DecentralizeExchangePage;

export const queryData = graphql`
  query MyQuery {
    decenterlizeExImg: file(
      relativePath: { eq: "decentralized-exchange-development.png" }
    ) {
      childImageSharp {
        gatsbyImageData
      }
    }
    site {
      siteMetadata {
        firestore {
          apiKey
          appId
          authDomain
          messagingSenderId
          projectId
          storageBucket
        }
      }
    }
    allMetaJson(
      filter: { slug: { eq: "decentralized-exchange-development" } }
    ) {
      nodes {
        metaTitle
        metaKeyword
        title
        slug
        description
      }
    }
  }
`;
